sql:
SELECT COUNT(*) AS Old_Tumors
FROM tumors
WHERE created_at < date('now', '-30 days');

SELECT tumors.tumor_type_id, patients.first_name, patients.last_name
FROM tumors
JOIN patients ON tumors.patient_id = patients.patient_id;

SELECT COUNT(DISTINCT patient_id) AS patients_under_observation
FROM follow_ups
WHERE status = 'Under Observation';

external_knowledge:
- More serious tumor cases refer to malignant tumors;
- The number of patients refers to the count of individuals sharing the same diagnosis;
- The term 'common' in this context means a higher frequency of occurrence or count of patients.

sql:
SELECT t.patient_id
FROM tumors t
WHERE t.tumor_type_id NOT IN (
    SELECT tt.tumor_type_id 
    FROM tumor_types tt
);

SELECT users.first_name, users.last_name, users.email
FROM users
JOIN medications ON users.user_id = medications.prescribed_by;

SELECT COUNT(DISTINCT f.patient_id) AS patient_count
FROM follow_ups f
WHERE f.follow_up_date = '2023-07-01';

SELECT patient_id, medication_name, COUNT(medication_id) AS total_prescriptions
FROM medications
GROUP BY patient_id, medication_name;

SELECT DISTINCT p.first_name, p.last_name, i.image_type 
FROM patients p
JOIN imaging i ON p.patient_id = i.patient_id;
